def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        if ratio > 2:
            penalty = 0
            for p in range(1, 5):
                penalty += ((ratio ** (2 * p + 1)) / (p * 3)) * ((-1) ** p)
            priorities[i] = ratio ** 4 + penalty + np.log1p(ratio)
        elif 1 < ratio <= 2:
            base_score = 0
            for q in range(1, 7):
                sign = (-1) ** (q + 1)
                base_score += sign * (np.sin(ratio * q) / (q ** 1.5))
            factor = 20 if ratio < 1.5 else 7
            priorities[i] = abs(base_score) * factor + np.exp(-ratio)
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1 if j % 2 == 0 else 1
                score += sign * (ratio ** j) / (j + 0.5)
            multiplier = 18 if ratio < 0.25 else 12 if ratio < 0.5 else 8 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 5):
                    extra += (np.cos(ratio * m) / (m + 1)) * (ratio ** m)
                priorities[i] += extra
        else:
            if item == 0:
                priorities[i] = 0
            else:
                nested_sum = 0
                for a in range(1, 4):
                    inner_sum = 0
                    for b in range(1, 5):
                        inner_sum += (a ** b) * np.tanh(ratio * b)
                    nested_sum += inner_sum / (a + 1)
                priorities[i] = np.abs(nested_sum) + ratio ** 2
    for idx in range(len(priorities)):
        if priorities[idx] > 50:
            priorities[idx] = 50 + np.log1p(priorities[idx] - 50)
    return priorities
